import{_ as s,H as i,f as e,i as n}from"./chunks/framework.BHvCMIhP.js";const b=JSON.parse('{"title":"eBPF","description":"","frontmatter":{},"headers":[],"relativePath":"../osLearning/27-eBPF.md","filePath":"../osLearning/27-eBPF.md","lastUpdated":1778496697000}'),l={name:"../osLearning/27-eBPF.md"};function t(p,a,r,o,h,c){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="ebpf" tabindex="-1">eBPF <a class="header-anchor" href="#ebpf" aria-label="Permalink to &quot;eBPF&quot;">​</a></h1><p>eBPF 是现代 Linux 最重要的可观测性和网络扩展机制之一。它允许你把受限的小程序加载到内核事件点上运行,不用改内核源码、不用写内核模块,就能观测 syscall、网络包、调度、文件系统,甚至实现高性能网络转发和安全策略。这一篇讲清楚:<strong>eBPF 程序怎么安全运行、kprobe/tracepoint/XDP/TC/uprobes 是什么、bpftrace 和 BCC 怎么用、它的边界在哪里</strong>。</p><blockquote><p>一句话先记住:<strong>eBPF = 安全地在内核事件点运行的小程序</strong>。Verifier 保证它不会崩内核,Maps 负责和用户态交换数据,Hooks 决定它挂在哪里。<strong>可观测性、网络、安全是 eBPF 三大主战场</strong>。它不是万能药,但它让&quot;线上看内核正在发生什么&quot;变得前所未有地低成本。</p></blockquote><hr><h2 id="一、为什么需要-ebpf" tabindex="-1">一、为什么需要 eBPF <a class="header-anchor" href="#一、为什么需要-ebpf" aria-label="Permalink to &quot;一、为什么需要 eBPF&quot;">​</a></h2><p>传统方式:</p><ul><li>加日志:要改代码、重启</li><li>strace:开销大,信息有限</li><li>内核模块:危险,容易崩内核</li><li>tcpdump:只能看包,看不到应用/内核关联</li></ul><p>eBPF:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>写一个小程序</span></span>
<span class="line"><span>加载到内核 hook 点</span></span>
<span class="line"><span>事件发生时执行</span></span>
<span class="line"><span>把统计结果写入 map</span></span>
<span class="line"><span>用户态读取 map</span></span></code></pre></div><p>不需要改业务代码,也不需要重启服务。</p><hr><h2 id="二、ebpf-架构" tabindex="-1">二、eBPF 架构 <a class="header-anchor" href="#二、ebpf-架构" aria-label="Permalink to &quot;二、eBPF 架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户态 loader</span></span>
<span class="line"><span>  → 加载 BPF bytecode</span></span>
<span class="line"><span>  → verifier 检查安全</span></span>
<span class="line"><span>  → JIT 编译成本机指令</span></span>
<span class="line"><span>  → attach 到 hook</span></span>
<span class="line"><span></span></span>
<span class="line"><span>内核事件发生</span></span>
<span class="line"><span>  → 执行 BPF 程序</span></span>
<span class="line"><span>  → 读写 BPF maps</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用户态</span></span>
<span class="line"><span>  → 读取 maps/perf buffer/ring buffer</span></span></code></pre></div><p>Verifier 检查:</p><ul><li>程序会终止</li><li>不越界访问</li><li>不随便解引用内核指针</li><li>栈大小受限</li><li>调用 helper 合法</li></ul><hr><h2 id="三、hook-类型" tabindex="-1">三、Hook 类型 <a class="header-anchor" href="#三、hook-类型" aria-label="Permalink to &quot;三、Hook 类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Hook</th><th>用途</th></tr></thead><tbody><tr><td>tracepoint</td><td>稳定内核跟踪点</td></tr><tr><td>kprobe/kretprobe</td><td>动态挂内核函数入口/返回</td></tr><tr><td>uprobe/uretprobe</td><td>挂用户态函数</td></tr><tr><td>XDP</td><td>网卡驱动早期处理包</td></tr><tr><td>TC</td><td>Linux 流量控制层</td></tr><tr><td>cgroup hooks</td><td>按 cgroup 过滤/观测</td></tr><tr><td>LSM</td><td>安全策略</td></tr><tr><td>perf event</td><td>CPU 性能事件</td></tr></tbody></table><h3 id="_3-1-tracepoint-vs-kprobe" tabindex="-1">3.1 tracepoint vs kprobe <a class="header-anchor" href="#_3-1-tracepoint-vs-kprobe" aria-label="Permalink to &quot;3.1 tracepoint vs kprobe&quot;">​</a></h3><p>tracepoint:</p><ul><li>接口较稳定</li><li>字段明确</li><li>推荐优先用</li></ul><p>kprobe:</p><ul><li>能挂几乎任意内核函数</li><li>内核版本变化可能导致函数名/参数变化</li></ul><hr><h2 id="四、bpftrace-入门" tabindex="-1">四、bpftrace 入门 <a class="header-anchor" href="#四、bpftrace-入门" aria-label="Permalink to &quot;四、bpftrace 入门&quot;">​</a></h2><p>统计进程 syscall:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftrace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tracepoint:syscalls:sys_enter_* { @[comm] = count(); }&#39;</span></span></code></pre></div><p>统计 open 文件:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftrace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tracepoint:syscalls:sys_enter_openat { printf(&quot;%s %s\\n&quot;, comm, str(args-&gt;filename)); }&#39;</span></span></code></pre></div><p>统计函数耗时:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftrace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kprobe:vfs_read { @start[tid] = nsecs; }</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kretprobe:vfs_read /@start[tid]/ {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  @lat = hist((nsecs - @start[tid]) / 1000);</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  delete(@start[tid]);</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&#39;</span></span></code></pre></div><p>bpftrace 适合快速排查和一次性脚本。</p><hr><h2 id="五、bcc-libbpf" tabindex="-1">五、BCC / libbpf <a class="header-anchor" href="#五、bcc-libbpf" aria-label="Permalink to &quot;五、BCC / libbpf&quot;">​</a></h2><p>BCC:</p><ul><li>Python 前端</li><li>内嵌 C 写 BPF 程序</li><li>工具丰富</li><li>依赖较重</li></ul><p>libbpf + CO-RE:</p><ul><li>现代生产推荐</li><li>编译一次,适配不同内核结构(BTF)</li><li>C/Rust/Go 生态都在跟进</li></ul><p>常见工具:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">execsnoop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensnoop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcpconnect</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcptop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">biolatency</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">runqlat</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">profile</span></span></code></pre></div><hr><h2 id="六、网络-xdp-和-tc" tabindex="-1">六、网络: XDP 和 TC <a class="header-anchor" href="#六、网络-xdp-和-tc" aria-label="Permalink to &quot;六、网络: XDP 和 TC&quot;">​</a></h2><p>XDP 在包进入协议栈前执行:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网卡驱动收到包</span></span>
<span class="line"><span>  → XDP</span></span>
<span class="line"><span>  → PASS / DROP / TX / REDIRECT</span></span>
<span class="line"><span>  → 内核网络栈</span></span></code></pre></div><p>用途:</p><ul><li>DDoS 丢包</li><li>负载均衡</li><li>包过滤</li><li>高性能转发</li></ul><p>TC 在协议栈稍后位置:</p><ul><li>更容易拿到 skb 上下文</li><li>适合策略、限速、服务网格数据面</li></ul><p>Cilium 就大量使用 eBPF 做 K8s 网络和安全策略。</p><hr><h2 id="七、可观测性场景" tabindex="-1">七、可观测性场景 <a class="header-anchor" href="#七、可观测性场景" aria-label="Permalink to &quot;七、可观测性场景&quot;">​</a></h2><h3 id="_7-1-syscall-慢" tabindex="-1">7.1 syscall 慢 <a class="header-anchor" href="#_7-1-syscall-慢" aria-label="Permalink to &quot;7.1 syscall 慢&quot;">​</a></h3><p>看某个 syscall 延迟直方图。</p><h3 id="_7-2-run-queue-延迟" tabindex="-1">7.2 run queue 延迟 <a class="header-anchor" href="#_7-2-run-queue-延迟" aria-label="Permalink to &quot;7.2 run queue 延迟&quot;">​</a></h3><p><code>runqlat</code> 看任务从 runnable 到真正上 CPU 等了多久。</p><h3 id="_7-3-磁盘延迟" tabindex="-1">7.3 磁盘延迟 <a class="header-anchor" href="#_7-3-磁盘延迟" aria-label="Permalink to &quot;7.3 磁盘延迟&quot;">​</a></h3><p><code>biolatency</code> 看块 IO 分布。</p><h3 id="_7-4-tcp-重传" tabindex="-1">7.4 TCP 重传 <a class="header-anchor" href="#_7-4-tcp-重传" aria-label="Permalink to &quot;7.4 TCP 重传&quot;">​</a></h3><p>跟踪 <code>tcp_retransmit_skb</code>。</p><h3 id="_7-5-锁竞争" tabindex="-1">7.5 锁竞争 <a class="header-anchor" href="#_7-5-锁竞争" aria-label="Permalink to &quot;7.5 锁竞争&quot;">​</a></h3><p>观察 futex、调度延迟、off-CPU 时间。</p><hr><h2 id="八、限制与风险" tabindex="-1">八、限制与风险 <a class="header-anchor" href="#八、限制与风险" aria-label="Permalink to &quot;八、限制与风险&quot;">​</a></h2><ol><li><strong>内核版本差异</strong>:能力随内核版本变化。</li><li><strong>Verifier 限制</strong>:不能写任意复杂逻辑。</li><li><strong>观测也有开销</strong>:高频 hook 打印会拖垮系统。</li><li><strong>字段不稳定</strong>:kprobe 依赖内核实现。</li><li><strong>权限要求高</strong>:通常需要 root/CAP_BPF/CAP_SYS_ADMIN。</li><li><strong>容器环境受限</strong>:云厂商可能禁用部分能力。</li></ol><hr><h2 id="九、使用原则" tabindex="-1">九、使用原则 <a class="header-anchor" href="#九、使用原则" aria-label="Permalink to &quot;九、使用原则&quot;">​</a></h2><ul><li>优先 tracepoint,再 kprobe</li><li>高频事件只做聚合,不要逐条 printf</li><li>线上脚本先在测试环境跑</li><li>设置过滤条件:pid/comm/cgroup</li><li>观测时间短而明确</li><li>复杂长期程序用 libbpf CO-RE</li></ul><hr><h2 id="十、ebpf-不替代什么" tabindex="-1">十、eBPF 不替代什么 <a class="header-anchor" href="#十、ebpf-不替代什么" aria-label="Permalink to &quot;十、eBPF 不替代什么&quot;">​</a></h2><p>eBPF 不替代:</p><ul><li>应用日志</li><li>指标系统</li><li>tracing</li><li>profiler</li><li>正确的容量规划</li></ul><p>它补的是&quot;应用看不到的内核层事实&quot;。</p><blockquote><p><strong>结论</strong>:eBPF 的价值不是炫技,而是把内核变成可观测、可编程的平台。排障时它能回答传统工具回答不了的问题:到底哪个进程、哪个 syscall、哪个内核路径、哪个网络事件在拖慢系统。</p></blockquote>`,73)])])}const u=s(l,[["render",t]]);export{b as __pageData,u as default};
